//
// This package provides functionality to process and compare arbitrary JSON
// values.  The JSONValue type is a wrapper that holds unmarshaled JSON data.
// You should *only* access such JSON data using visitors with Accept, compare
// such JSON data using Equal, or validate such JSON data using Validate.
package jsondata

import (
	"fmt"
)

// A Visitor is used by Accept to process arbitrary values that only contain
// data of valid JSON types.  The Map and Slice methods may recursively call
// Accept on their constituent elements.
type Visitor[T any] interface {
	Map(map[string]JSONValue) (T, error)
	Slice([]JSONValue) (T, error)
	Bool(bool) (T, error)
	Float64(float64) (T, error)
	String(string) (T, error)
	Null() (T, error)
}

// Accept applies the given input visitor to the given input value by calling
// the appropriate visitor method on a copy of the input value given the input
// value's type. Returns an error if value is of a type that is not a valid JSON
// type or if the visitor method returns an error.
//
// As the visitor methods receive *copies* of the JSON values, any modifications
// will not affect the original JSON value.
//
// Note that this is a function so that the visitor and return value can be a
// generic type.  Go does not allow methods to have generic types unrelated to
// the receiver type.
func Accept[T any](value JSONValue, visitor Visitor[T]) (T, error) {
	wrap := func(v any) JSONValue {
		switch v := v.(type) {
		case JSONValue:
			return v
		default:
			return JSONValue{v}
		}
	}

	switch val := value.data.(type) {
	case map[string]any:
		m := make(map[string]JSONValue)
		for k, v := range val {
			m[k] = wrap(v)
		}
		return visitor.Map(m)
	case []any:
		s := make([]JSONValue, len(val))
		for i, v := range val {
			s[i] = wrap(v)
		}
		return visitor.Slice(s)
	case float64:
		return visitor.Float64(val)
	case bool:
		return visitor.Bool(val)
	case string:
		return visitor.String(val)
	case nil:
		return visitor.Null()
	default:
		var zero T
		return zero, fmt.Errorf("invalid JSON value: %s", value.data)
	}
}

// Structured logger that allows you to set the log level
// and colorize the output.  You may choose to use this or
// not and you may modify it in any way.
//
// To use this, set up your logger as follows:
//
//	logOpts := &logger.PrettyHandlerOptions{
//	    Level:    slog.LevelDebug, // log level you want
//	    Colorize: true,            // true or false
//	}
//
// handler := logger.NewPrettyHandler(os.Stdout, logOpts)
// logger := slog.New(handler)
// slog.SetDefault(logger)
package logger

import (
	"context"
	"fmt"
	"io"
	"log/slog"
	"runtime"
	"slices"
	"strings"
	"sync"
	"time"
	"unicode"
)

/*
 * Works on Linux, Windows 11, and MacOS 13
 *  (Does not work in Windows 10)
 */

// Escape codes for colorizing output.
const (
	Reset  = "\033[0m"
	Red    = "\033[31m"
	Green  = "\033[32m"
	Yellow = "\033[33m"
	Blue   = "\033[34m"
	Purple = "\033[35m"
	Cyan   = "\033[36m"
	Gray   = "\033[37m"
	White  = "\033[97m"
)

// PrettyHandlerOptions provides options for the PrettyHandler
type PrettyHandlerOptions struct {
	AddSource   bool
	Level       slog.Leveler
	ReplaceAttr func([]string, slog.Attr) slog.Attr
	Colorize    bool
}

// PrettyHandler is an slog.Handler that pretty-prints log records using color.
// Based upon:
//
//	https://github.com/golang/example/blob/master/slog-handler-guide/README.md
type PrettyHandler struct {
	pool *sync.Pool
	opts *PrettyHandlerOptions
	goas []groupOrAttrs
	mu   *sync.Mutex
	out  io.Writer
}

// groupOrAttrs holds either a group name or a list of slog.Attrs.
type groupOrAttrs struct {
	group string      // group name if non-empty
	attrs []slog.Attr // attrs if non-empty
}

// needsQuoting reports whether the string s needs quoting.
func needsQuoting(s string) bool {
	if len(s) == 0 {
		return true
	}
	for _, r := range s {
		if unicode.IsSpace(r) || strings.ContainsRune("!\"#$%&'()*+,-/:;<=>?@[\\]^`{|}~", r) {
			return true
		}
	}
	return false
}

// initPool initializes the pool of buffers for the PrettyHandler.
func (h *PrettyHandler) initPool() {
	h.pool = &sync.Pool{
		New: func() any {
			b := make([]byte, 0, 1024)
			return &b
		},
	}
}

// allocBuf returns a buffer from the pool.
func (h *PrettyHandler) allocBuf() *[]byte {
	if h.pool == nil {
		b := make([]byte, 0, 1024)
		return &b
	}

	return h.pool.Get().(*[]byte)
}

// freeBuf returns a buffer to the pool.
func (h *PrettyHandler) freeBuf(b *[]byte) {
	if h.pool == nil {
		return
	}

	// To reduce peak allocation, return only smaller buffers to the pool.
	const maxBufferSize = 16 << 10
	if cap(*b) <= maxBufferSize {
		*b = (*b)[:0]
		h.pool.Put(b)
	}
}

// qappendf appends a quoted string to the given buffer.
func qappendf(buf []byte, groups []string, val string) []byte {
	pstr := strings.Join(groups, ".")
	if len(groups) > 0 {
		pstr = fmt.Sprintf("%s.", pstr)
	}
	str := fmt.Sprintf("%s%s", pstr, val)
	if needsQuoting(str) {
		buf = fmt.Appendf(buf, "%q", str)
	} else {
		buf = fmt.Appendf(buf, "%s", str)
	}
	return buf
}

// appendAttr appends an attribute to the given buffer.
func (h *PrettyHandler) appendAttr(buf []byte, a slog.Attr, groups []string) []byte {
	// Resolve the Attr's value before doing anything else.
	a.Value = a.Value.Resolve()

	// Call ReplaceAttr, if provided.
	if rep := h.opts.ReplaceAttr; rep != nil && a.Value.Kind() != slog.KindGroup {
		gs := slices.Clone(groups)
		a = rep(gs, a)
		a.Value = a.Value.Resolve()
	}

	// Ignore empty Attrs.
	if a.Equal(slog.Attr{}) {
		return buf
	}

	switch a.Value.Kind() {
	case slog.KindString:
		// Prefix the attribute with a space
		buf = append(buf, " "...)

		// Output key=value
		buf = qappendf(buf, groups, a.Key)
		buf = append(buf, "="...)
		buf = qappendf(buf, []string{}, a.Value.String())
	case slog.KindTime:
		// Prefix the attribute with a space
		buf = append(buf, " "...)

		// Output key=value
		buf = qappendf(buf, groups, a.Key)
		buf = append(buf, "="...)

		// Write times in a standard way, without the monotonic time.
		buf = fmt.Appendf(buf, "%s", a.Value.Time().Format(time.RFC3339Nano))
	case slog.KindGroup:
		attrs := a.Value.Group()
		// Ignore empty groups.
		if len(attrs) == 0 {
			return buf
		}
		// If the key is non-empty, add group to groups.
		if a.Key != "" {
			groups = append(groups, a.Key)
		}

		// Output group's attributes.
		for _, ga := range attrs {
			buf = h.appendAttr(buf, ga, groups)
		}
	default:
		// Prefix the attribute with a space
		buf = append(buf, " "...)

		// Output key=value
		buf = qappendf(buf, groups, a.Key)
		buf = append(buf, "="...)
		buf = fmt.Appendf(buf, "%s", a.Value)
	}

	return buf
}

// Enabled returns true if the logging level is enabled.
func (h *PrettyHandler) Enabled(ctx context.Context, level slog.Level) bool {
	return level >= h.opts.Level.Level()
}

// Handle writes the record to the output.
func (h *PrettyHandler) Handle(ctx context.Context, r slog.Record) error {
	// Allocate a buffer for the record from the pool.
	bufp := h.allocBuf()
	buf := *bufp
	defer func() {
		*bufp = buf
		h.freeBuf(bufp)
	}()

	groups := make([]string, 0)

	if h.opts.Colorize {
		// Set the color based on the level of the record.
		if r.Level == slog.LevelError {
			buf = append(buf, Red...)

// Package tests provides a comprehensive testing harness for OwlDB implementations.
// It includes utilities for starting/stopping servers, making HTTP requests,
// and validating responses according to the OwlDB specification.
package tests

import (
	"bufio"
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"sync"
	"time"
)

// TestResult represents the outcome of a single test
type TestResult struct {
	Name     string        `json:"name"`
	Passed   bool          `json:"passed"`
	Duration time.Duration `json:"duration"`
	Error    string        `json:"error,omitempty"`
	Details  string        `json:"details,omitempty"`
}

// TestSuite represents a collection of related tests
type TestSuite struct {
	Name    string       `json:"name"`
	Results []TestResult `json:"results"`
}

// TestHarness manages the test server and executes tests
type TestHarness struct {
	ServerBinary string
	SchemaFile   string
	TokenFile    string
	Port         int
	ServerCmd    *exec.Cmd
	BaseURL      string
	Token        string
	mu           sync.Mutex
}

// WaitForServer is a public wrapper for waitForServer
func (h *TestHarness) WaitForServer(timeout time.Duration) error {
	return h.waitForServer(timeout)
}

// NewTestHarness creates a new test harness
func NewTestHarness(serverBinary, schemaFile, tokenFile string, port int) *TestHarness {
	return &TestHarness{
		ServerBinary: serverBinary,
		SchemaFile:   schemaFile,
		TokenFile:    tokenFile,
		Port:         port,
		BaseURL:      fmt.Sprintf("http://localhost:%d", port),
	}
}

// StartServer starts the OwlDB server
func (h *TestHarness) StartServer(ctx context.Context) error {
	h.mu.Lock()
	defer h.mu.Unlock()

	args := []string{
		"-p", fmt.Sprintf("%d", h.Port),
		"-s", h.SchemaFile,
	}
	if h.TokenFile != "" {
		args = append(args, "-t", h.TokenFile)
	}

	h.ServerCmd = exec.CommandContext(ctx, h.ServerBinary, args...)
	h.ServerCmd.Stdout = os.Stdout
	h.ServerCmd.Stderr = os.Stderr

	if err := h.ServerCmd.Start(); err != nil {
		return fmt.Errorf("failed to start server: %w", err)
	}

	// Wait for server to be ready
	return h.waitForServer(10 * time.Second)
}

// waitForServer waits for the server to accept connections
func (h *TestHarness) waitForServer(timeout time.Duration) error {
	deadline := time.Now().Add(timeout)
	for time.Now().Before(deadline) {
		resp, err := http.Get(h.BaseURL + "/v1/")
		if err == nil {
			resp.Body.Close()
			return nil
		}
		time.Sleep(100 * time.Millisecond)
	}
	return fmt.Errorf("server did not start within %v", timeout)
}

// StopServer stops the OwlDB server
func (h *TestHarness) StopServer() error {
	h.mu.Lock()
	defer h.mu.Unlock()

	if h.ServerCmd != nil && h.ServerCmd.Process != nil {
		if err := h.ServerCmd.Process.Signal(os.Interrupt); err != nil {
			return h.ServerCmd.Process.Kill()
		}
		h.ServerCmd.Wait()
	}
	return nil
}

// SetToken sets the bearer token for authenticated requests
func (h *TestHarness) SetToken(token string) {
	h.Token = token
}

// HTTPRequest makes an HTTP request and returns the response
func (h *TestHarness) HTTPRequest(method, path string, body interface{}) (*HTTPResponse, error) {
	var bodyReader io.Reader
	if body != nil {
		jsonBody, err := json.Marshal(body)
		if err != nil {
			return nil, fmt.Errorf("failed to marshal body: %w", err)
		}
		bodyReader = bytes.NewReader(jsonBody)
	}

	url := h.BaseURL + path
	req, err := http.NewRequest(method, url, bodyReader)
	if err != nil {
		return nil, fmt.Errorf("failed to create request: %w", err)
	}

	if body != nil {
		req.Header.Set("Content-Type", "application/json")
	}
	if h.Token != "" {
		req.Header.Set("Authorization", "Bearer "+h.Token)
	}

	client := &http.Client{Timeout: 30 * time.Second}
	resp, err := client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("request failed: %w", err)
	}
	defer resp.Body.Close()

	respBody, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("failed to read response: %w", err)
	}

	return &HTTPResponse{
		StatusCode:  resp.StatusCode,
		Headers:     resp.Header,
		Body:        respBody,
		ContentType: resp.Header.Get("Content-Type"),
	}, nil
}

// HTTPResponse represents an HTTP response
type HTTPResponse struct {
	StatusCode  int
	Headers     http.Header
	Body        []byte
	ContentType string
}

// JSON parses the response body as JSON
func (r *HTTPResponse) JSON() (map[string]interface{}, error) {
	var result map[string]interface{}
	if err := json.Unmarshal(r.Body, &result); err != nil {
		return nil, err
	}
	return result, nil
}

// JSONArray parses the response body as a JSON array
func (r *HTTPResponse) JSONArray() ([]interface{}, error) {
	var result []interface{}
	if err := json.Unmarshal(r.Body, &result); err != nil {
		return nil, err
	}
	return result, nil
}

// SSEClient handles Server-Sent Events connections
type SSEClient struct {
	URL      string
	Token    string
	Events   chan SSEEvent
	Done     chan struct{}
	Response *http.Response
	mu       sync.Mutex
}

// SSEEvent represents a Server-Sent Event
type SSEEvent struct {
	Event string
	Data  string
	ID    string
}

// NewSSEClient creates a new SSE client
func NewSSEClient(url, token string) *SSEClient {
	return &SSEClient{
		URL:    url,
		Token:  token,
		Events: make(chan SSEEvent, 100),
		Done:   make(chan struct{}),
	}
}

// Connect connects to the SSE endpoint
func (c *SSEClient) Connect(ctx context.Context) error {
	req, err := http.NewRequestWithContext(ctx, "GET", c.URL, nil)
	if err != nil {
		return err
	}

	if c.Token != "" {
		req.Header.Set("Authorization", "Bearer "+c.Token)
	}
	req.Header.Set("Accept", "text/event-stream")

	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		return err
	}

	if resp.StatusCode != http.StatusOK {
		resp.Body.Close()
		return fmt.Errorf("unexpected status code: %d", resp.StatusCode)

package tests

import (
	"encoding/json"
	"fmt"
	"net/http"
	"strings"
	"testing"
	"time"
)

// IntegrationTests contains comprehensive integration tests for all HTTP methods
type IntegrationTests struct {
	harness *TestHarness
	t       *testing.T
}

// NewIntegrationTests creates a new integration test suite
func NewIntegrationTests(harness *TestHarness, t *testing.T) *IntegrationTests {
	return &IntegrationTests{harness: harness, t: t}
}

// RunAll runs all integration tests
func (i *IntegrationTests) RunAll() []TestResult {
	var results []TestResult

	tests := []struct {
		name string
		fn   func() error
	}{
		{"PostDocumentReturnsURI", i.TestPostDocumentReturnsURI},
		{"PostDocumentCreatesDocument", i.TestPostDocumentCreatesDocument},
		{"PostDocumentNestedCollection", i.TestPostDocumentNestedCollection},
		{"PostDocumentWithData", i.TestPostDocumentWithData},
		{"PatchArrayAddDuplicate", i.TestPatchArrayAddDuplicate},
		{"PatchObjectAddNested", i.TestPatchObjectAddNested},
		{"PatchMultipleOperations", i.TestPatchMultipleOperations},
		{"PatchResponseFormat", i.TestPatchResponseFormat},
		{"OptionsCollectionPath", i.TestOptionsCollectionPath},
		{"OptionsCORSHeaders", i.TestOptionsCORSHeaders},
		{"AuthLoginReturnsToken", i.TestAuthLoginReturnsToken},
		{"AuthUnauthorizedWithoutToken", i.TestAuthUnauthorizedWithoutToken},
		{"CollectionQueryWithIntervalExclusive", i.TestCollectionQueryWithIntervalExclusive},
		{"CollectionQueryOrdering", i.TestCollectionQueryOrdering},
		{"DocumentMetadataCreatedBy", i.TestDocumentMetadataCreatedBy},
		{"DocumentMetadataLastModifiedBy", i.TestDocumentMetadataLastModifiedBy},
		{"ErrorResponseJSON", i.TestErrorResponseJSON},
		{"Error400BadRequest", i.TestError400BadRequest},
		{"Error404NotFound", i.TestError404NotFound},
	}

	for _, test := range tests {
		start := time.Now()
		err := test.fn()
		duration := time.Since(start)

		result := TestResult{
			Name:     test.name,
			Passed:   err == nil,
			Duration: duration,
		}
		if err != nil {
			result.Error = err.Error()
		}
		results = append(results, result)

		if i.t != nil {
			if err != nil {
				i.t.Errorf("%s: %v", test.name, err)
			} else {
				i.t.Logf("%s: PASSED (%v)", test.name, duration)
			}
		}
	}

	return results
}

// POST Integration Tests

func (i *IntegrationTests) TestPostDocumentReturnsURI() error {
	dbName := GenerateTestDBName()
	defer i.harness.DeleteDatabase(dbName)

	if err := i.harness.CreateDatabase(dbName); err != nil {
		return err
	}

	doc := map[string]interface{}{"data": "test"}
	resp, err := i.harness.HTTPRequest("POST", "/v1/"+dbName+"/", doc)
	if err != nil {
		return err
	}

	// POST is optional - if server returns 405, skip this test
	if resp.StatusCode == http.StatusMethodNotAllowed {
		return nil
	}

	if resp.StatusCode != http.StatusCreated && resp.StatusCode != http.StatusOK {
		return fmt.Errorf("expected status 201 or 200, got %d: %s", resp.StatusCode, string(resp.Body))
	}

	result, err := resp.JSON()
	if err != nil {
		return fmt.Errorf("failed to parse response: %w", err)
	}

	// Check for uri field
	uri, hasUri := result["uri"].(string)
	path, hasPath := result["path"].(string)

	if !hasUri && !hasPath {
		return fmt.Errorf("response missing uri/path field: %v", result)
	}

	// Just verify uri/path is non-empty (the server may strip the db prefix per P2 spec)
	if hasUri && uri == "" {
		return fmt.Errorf("uri field is empty")
	}
	if hasPath && path == "" {
		return fmt.Errorf("path field is empty")
	}

	return nil
}

func (i *IntegrationTests) TestPostDocumentCreatesDocument() error {
	dbName := GenerateTestDBName()
	defer i.harness.DeleteDatabase(dbName)

	if err := i.harness.CreateDatabase(dbName); err != nil {
		return err
	}

	doc := map[string]interface{}{"data": "posted"}
	resp, err := i.harness.HTTPRequest("POST", "/v1/"+dbName+"/", doc)
	if err != nil {
		return err
	}

	// POST is optional
	if resp.StatusCode == http.StatusMethodNotAllowed {
		return nil
	}

	if resp.StatusCode != http.StatusCreated && resp.StatusCode != http.StatusOK {
		return fmt.Errorf("POST failed with status %d", resp.StatusCode)
	}

	result, err := resp.JSON()
	if err != nil {
		return err
	}

	// Extract the document path from response.
	// The server may return a stripped path (without /v1/<dbname> prefix per P2 spec)
	// or a full path. We need to construct <dbname>/<docname> for retrieval.
	var docPath string
	if uri, ok := result["uri"].(string); ok {
		stripped := strings.TrimPrefix(uri, "/v1/")
		// If the path still contains the dbName, use it as-is
		if strings.HasPrefix(stripped, dbName) {
			docPath = stripped
		} else {
			// Stripped path: prepend dbName
			docPath = dbName + "/" + strings.TrimPrefix(stripped, "/")
		}
	} else if path, ok := result["path"].(string); ok {
		stripped := strings.TrimPrefix(path, "/v1/")
		if strings.HasPrefix(stripped, dbName) {
			docPath = stripped
		} else {
			docPath = dbName + "/" + strings.TrimPrefix(stripped, "/")
		}
	} else {
		return fmt.Errorf("no path returned")
	}

	// Verify document was created
	retrievedDoc, err := i.harness.GetDocument(docPath)
	if err != nil {
		return fmt.Errorf("failed to retrieve POSTed document: %w", err)
	}

	docData, ok := retrievedDoc["doc"].(map[string]interface{})
	if !ok {
		docData = retrievedDoc
	}

	if docData["data"] != "posted" {
		return fmt.Errorf("document content mismatch")
	}

	return nil
}

