// Concurrent PATCH Tests

func (c *ConcurrentTests) TestConcurrentPATCHsSameDocument() error {
	dbName := GenerateTestDBName()
	defer c.harness.DeleteDatabase(dbName)

	if err := c.harness.CreateDatabase(dbName); err != nil {
		return err
	}

	// Create document with array
	doc := map[string]interface{}{
		"tags": []interface{}{},
	}
	if err := c.harness.PutDocument(dbName+"/doc1", doc); err != nil {
		return err
	}

	// Launch multiple concurrent PATCH operations
	numGoroutines := 10
	var wg sync.WaitGroup
	errors := make(chan error, numGoroutines)

	for i := 0; i < numGoroutines; i++ {
		wg.Add(1)
		go func(idx int) {
			defer wg.Done()
			patches := []map[string]interface{}{
				{"op": "ArrayAdd", "path": "/tags", "value": fmt.Sprintf("tag%d", idx)},
			}
			resp, err := c.harness.PatchDocument(dbName+"/doc1", patches)
			if err != nil {
				errors <- fmt.Errorf("goroutine %d: %w", idx, err)
				return
			}
			if resp.StatusCode != http.StatusOK {
				errors <- fmt.Errorf("goroutine %d: unexpected status %d", idx, resp.StatusCode)
			}
		}(i)
	}

	wg.Wait()
	close(errors)

	// Check for errors
	for err := range errors {
		return err
	}

	// Verify the document state
	result, err := c.harness.GetDocument(dbName + "/doc1")
	if err != nil {
		return err
	}

	docData, ok := result["doc"].(map[string]interface{})
	if !ok {
		docData = result
	}

	tags, ok := docData["tags"].([]interface{})
	if !ok {
		return fmt.Errorf("tags field not found or not array")
	}

	// All unique tags should be present (ArrayAdd doesn't add duplicates)
	if len(tags) == 0 {
		return fmt.Errorf("expected some tags, got none")
	}

	return nil
}

func (c *ConcurrentTests) TestConcurrentPATCHsDifferentDocuments() error {
	dbName := GenerateTestDBName()
	defer c.harness.DeleteDatabase(dbName)

