			return err
		}
	}

	// Launch concurrent PATCH operations on different documents
	numGoroutines := 20
	var wg sync.WaitGroup
	errors := make(chan error, numGoroutines)

	for i := 0; i < numGoroutines; i++ {
		wg.Add(1)
		go func(idx int) {
			defer wg.Done()
			docIdx := idx % numDocs
			patches := []map[string]interface{}{
				{"op": "ArrayAdd", "path": "/tags", "value": fmt.Sprintf("tag%d", idx)},
			}
			resp, err := c.harness.PatchDocument(fmt.Sprintf("%s/doc%d", dbName, docIdx), patches)
			if err != nil {
				errors <- fmt.Errorf("goroutine %d: %w", idx, err)
				return
			}
			if resp.StatusCode != http.StatusOK {
				errors <- fmt.Errorf("goroutine %d: unexpected status %d", idx, resp.StatusCode)
			}
		}(i)
	}

	wg.Wait()
	close(errors)

	for err := range errors {
		return err
	}

	return nil
}

