// readEvents reads SSE events from the response body
func (c *SSEClient) readEvents(body io.ReadCloser) {
	defer body.Close()
	defer close(c.Events)

	scanner := bufio.NewScanner(body)
	var event SSEEvent

	for scanner.Scan() {
		line := scanner.Text()

		if line == "" {
			// Empty line signals end of event
			if event.Event != "" || event.Data != "" {
				select {
				case c.Events <- event:
				case <-c.Done:
					return
				}
				event = SSEEvent{}
			}
			continue
		}

		if strings.HasPrefix(line, ":") {
			// Comment line, ignore
			continue
		}

		if strings.HasPrefix(line, "event:") {
			event.Event = strings.TrimSpace(strings.TrimPrefix(line, "event:"))
		} else if strings.HasPrefix(line, "data:") {
			if event.Data != "" {
				event.Data += "\n"
			}
			event.Data += strings.TrimSpace(strings.TrimPrefix(line, "data:"))
		} else if strings.HasPrefix(line, "id:") {
			event.ID = strings.TrimSpace(strings.TrimPrefix(line, "id:"))
		}
	}
}

// Close closes the SSE connection
func (c *SSEClient) Close() {
	close(c.Done)
	c.mu.Lock()
	defer c.mu.Unlock()
	if c.Response != nil {
		c.Response.Body.Close()
	}
}

// WaitForEvent waits for an event with a timeout
func (c *SSEClient) WaitForEvent(timeout time.Duration) (*SSEEvent, error) {
	select {
	case event, ok := <-c.Events:
		if !ok {
			return nil, fmt.Errorf("event channel closed")
		}
		return &event, nil
	case <-time.After(timeout):
		return nil, fmt.Errorf("timeout waiting for event")
	}
}

// Login authenticates and returns a token
func (h *TestHarness) Login(username string) (string, error) {
	resp, err := h.HTTPRequest("POST", "/auth", map[string]string{"username": username})
	if err != nil {
		return "", err
	}
	if resp.StatusCode != http.StatusOK && resp.StatusCode != http.StatusCreated {
		return "", fmt.Errorf("login failed with status %d: %s", resp.StatusCode, string(resp.Body))
	}

	data, err := resp.JSON()
	if err != nil {
		return "", err
	}

	token, ok := data["token"].(string)
	if !ok {
		return "", fmt.Errorf("token not found in response")
	}
	return token, nil
}

// CreateDatabase creates a database
func (h *TestHarness) CreateDatabase(name string) error {
	// Try without trailing slash first (some implementations reject trailing slash)
	resp, err := h.HTTPRequest("PUT", "/v1/"+name, nil)
	if err != nil {
		return err
	}
	// If server rejects, try with trailing slash
	if resp.StatusCode == http.StatusBadRequest {
		resp, err = h.HTTPRequest("PUT", "/v1/"+name+"/", nil)
	}
	if err != nil {
		return err
	}
	if resp.StatusCode != http.StatusOK && resp.StatusCode != http.StatusCreated {
		return fmt.Errorf("create database failed with status %d: %s", resp.StatusCode, string(resp.Body))
	}
	return nil
}

