func (s *SequentialTests) TestGetCollectionWithIntervalHighOnly() error {
	dbName := GenerateTestDBName()
	defer s.harness.DeleteDatabase(dbName)

	if err := s.harness.CreateDatabase(dbName); err != nil {
		return err
	}

	docs := []string{"aaa", "bbb", "ccc", "ddd", "eee"}
	for _, name := range docs {
		if err := s.harness.PutDocument(dbName+"/"+name, map[string]interface{}{"name": name}); err != nil {
			return err
		}
	}

	// Get interval [,ccc] - Note: many implementations use exclusive upper bound
	// so this returns aaa, bbb (2 docs) rather than aaa, bbb, ccc (3 docs)
	result, err := s.harness.GetCollection(dbName+"/", "[,ccc]")
	if err != nil {
		return err
	}

	// Accept 2 (exclusive upper) or 3 (inclusive upper) documents
	if len(result) < 2 || len(result) > 3 {
		return fmt.Errorf("expected 2-3 documents for interval [,ccc], got %d", len(result))
	}
	return nil
}

// Nested Path Tests

func (s *SequentialTests) TestNestedDocumentsAndCollections() error {
	dbName := GenerateTestDBName()
	defer s.harness.DeleteDatabase(dbName)

	if err := s.harness.CreateDatabase(dbName); err != nil {
		return err
	}

	// Create parent document
	if err := s.harness.PutDocument(dbName+"/parent", map[string]interface{}{"type": "parent"}); err != nil {
		return err
	}

	// Create collection first (required before adding documents to it)
	if err := s.harness.CreateCollection(dbName + "/parent/children/"); err != nil {
		return fmt.Errorf("create collection failed: %w", err)
	}

	// Create nested document in collection
	if err := s.harness.PutDocument(dbName+"/parent/children/child1", map[string]interface{}{"type": "child"}); err != nil {
		return err
	}

	// Retrieve nested document
	result, err := s.harness.GetDocument(dbName + "/parent/children/child1")
	if err != nil {
		return err
	}

	docData, ok := result["doc"].(map[string]interface{})
	if !ok {
		docData = result
	}

	if docData["type"] != "child" {
		return fmt.Errorf("expected type=child, got %v", docData["type"])
	}
	return nil
}

func (s *SequentialTests) TestDeepNestedPath() error {
	dbName := GenerateTestDBName()
	defer s.harness.DeleteDatabase(dbName)

	if err := s.harness.CreateDatabase(dbName); err != nil {
		return err
	}

	// Create deep nested path: db/doc1/col1/doc2/col2/doc3
	// Need to create each level: doc1 -> col1/ -> doc2 -> col2/ -> doc3

	// Create doc1
	if err := s.harness.PutDocument(dbName+"/doc1", map[string]interface{}{"level": 1}); err != nil {
		return fmt.Errorf("create doc1 failed: %w", err)
	}

	// Create col1 collection
	if err := s.harness.CreateCollection(dbName + "/doc1/col1/"); err != nil {
		return fmt.Errorf("create col1 failed: %w", err)
	}

	// Create doc2 in col1
	if err := s.harness.PutDocument(dbName+"/doc1/col1/doc2", map[string]interface{}{"level": 2}); err != nil {
		return fmt.Errorf("create doc2 failed: %w", err)
	}

	// Create col2 collection under doc2
	if err := s.harness.CreateCollection(dbName + "/doc1/col1/doc2/col2/"); err != nil {
		return fmt.Errorf("create col2 failed: %w", err)
	}

	// Create doc3 in col2
	path := dbName + "/doc1/col1/doc2/col2/doc3"
	doc := map[string]interface{}{"depth": 3}

	if err := s.harness.PutDocument(path, doc); err != nil {
		return fmt.Errorf("create doc3 failed: %w", err)
	}

	result, err := s.harness.GetDocument(path)
	if err != nil {
		return err
	}

	docData, ok := result["doc"].(map[string]interface{})
	if !ok {
		docData = result
	}

	depth, ok := docData["depth"].(float64)
	if !ok || depth != 3 {
		return fmt.Errorf("expected depth=3, got %v", docData["depth"])
	}
	return nil
}

// POST Document Tests

func (s *SequentialTests) TestPostDocument() error {
	dbName := GenerateTestDBName()
	defer s.harness.DeleteDatabase(dbName)

	if err := s.harness.CreateDatabase(dbName); err != nil {
		return err
	}

	doc := map[string]interface{}{"data": "posted"}
	resp, err := s.harness.HTTPRequest("POST", "/v1/"+dbName+"/", doc)
	if err != nil {
		return err
	}

	// POST is optional - if server returns 405, skip this test
	if resp.StatusCode == http.StatusMethodNotAllowed {
		return nil // Skip - POST not implemented
	}

	if resp.StatusCode != http.StatusCreated && resp.StatusCode != http.StatusOK {
		return fmt.Errorf("expected status 201 or 200, got %d: %s", resp.StatusCode, string(resp.Body))
	}

	// Check response contains URI/path
	result, err := resp.JSON()
	if err != nil {
		return fmt.Errorf("failed to parse response: %w", err)
	}

	// Look for uri field
	if _, ok := result["uri"]; !ok {
		if _, ok := result["path"]; !ok {
			return fmt.Errorf("response missing uri/path field: %v", result)
		}
	}
	return nil
}

