func (s *SequentialTests) TestPatchArrayAdd() error {
	dbName := GenerateTestDBName()
	defer s.harness.DeleteDatabase(dbName)

	if err := s.harness.CreateDatabase(dbName); err != nil {
		return err
	}

	doc := map[string]interface{}{
		"tags": []interface{}{"a", "b"},
	}
	if err := s.harness.PutDocument(dbName+"/doc1", doc); err != nil {
		return err
	}

	patches := []map[string]interface{}{
		{"op": "ArrayAdd", "path": "/tags", "value": "c"},
	}
	resp, err := s.harness.PatchDocument(dbName+"/doc1", patches)
	if err != nil {
		return err
	}

	if resp.StatusCode != http.StatusOK {
		return fmt.Errorf("expected status 200, got %d: %s", resp.StatusCode, string(resp.Body))
	}

	result, err := resp.JSON()
	if err != nil {
		return err
	}

	if patchFailed, ok := result["patchFailed"].(bool); ok && patchFailed {
		return fmt.Errorf("patch failed: %v", result["message"])
	}

	// Verify the change
	doc2, err := s.harness.GetDocument(dbName + "/doc1")
	if err != nil {
		return err
	}

	docData, ok := doc2["doc"].(map[string]interface{})
	if !ok {
		docData = doc2
	}

	tags, ok := docData["tags"].([]interface{})
	if !ok {
		return fmt.Errorf("tags field not found or not array: %v", docData)
	}

	if len(tags) != 3 {
		return fmt.Errorf("expected 3 tags, got %d", len(tags))
	}
	return nil
}

